import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.BKDXG6j6.js";const u=JSON.parse('{"title":"System Design & Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"interview/system-design.md","filePath":"interview/system-design.md","lastUpdated":null}'),s={name:"interview/system-design.md"};function n(r,e,l,c,g,d){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="system-design-architecture" tabindex="-1">System Design &amp; Architecture <a class="header-anchor" href="#system-design-architecture" aria-label="Permalink to &quot;System Design &amp; Architecture&quot;">​</a></h1><p>System design questions test a developer&#39;s ability to abstract a massive feature or app into scalable, robust technical components.</p><h2 id="general-approach" tabindex="-1">General Approach <a class="header-anchor" href="#general-approach" aria-label="Permalink to &quot;General Approach&quot;">​</a></h2><p>When given an Android system design prompt (e.g., &quot;Design the Twitter Feed&quot; or &quot;Design a Ride-Sharing Map App&quot;):</p><ol><li><strong>Clarify Requirements:</strong> Ask questions. Is offline support required? Are we dealing with real-time sockets or polling? Image uploads?</li><li><strong>High-Level Diagram:</strong> Propose standard MVVM + Clean Architecture flow. Note where Repositories sit and how UseCases abstract logic.</li><li><strong>Data Layer Strategy:</strong> Discuss API interactions (REST vs GraphQL/WebSockets) and local persistence (Room). Explain the caching strategy (Single Source of Truth paradigm).</li><li><strong>Offline support/Sync (crucial):</strong> How does the app handle a dropped connection? (E.g., Save API actions to Room, push to server via WorkManager when connection returns).</li><li><strong>Pagination:</strong> How are massive lists rendered without memory limits blowing up? (Paging 3 + RemoteMediator).</li><li><strong>Performance &amp; Security:</strong> Image Caching (Coil/Glide), Certificate Pinning, Obfuscation (R8), Encryption (EncryptedSharedPreferences).</li></ol><hr><h2 id="scenario-a-design-an-offline-first-chat-application" tabindex="-1">Scenario A: Design an Offline-First Chat Application <a class="header-anchor" href="#scenario-a-design-an-offline-first-chat-application" aria-label="Permalink to &quot;Scenario A: Design an Offline-First Chat Application&quot;">​</a></h2><p><strong>Requirements:</strong></p><ul><li>Send/Receive distinct text messages.</li><li>Must work robustly without internet connection (queueing).</li></ul><p><strong>Architecture Components:</strong></p><ol><li><strong>Network:</strong> Use WebSockets or Server-Sent Events (SSE) for real-time delivery, not REST polling. Fallback to FCM (Firebase Cloud Messaging) pushing wake locks if the app is killed.</li><li><strong>Local Database:</strong> Room Database. Specifically, a <code>Message</code> table with a <code>sync_status</code> column (<code>PENDING</code>, <code>SENT</code>, <code>FAILED</code>).</li><li><strong>Single Source of Truth:</strong><ul><li>The UI absolutely NEVER observes the network directly.</li><li>The UI <em>only</em> observes a Flow from the Room DAO (<code>SELECT * FROM messages WHERE chat_id = X ORDER BY timestamp ASC</code>).</li><li>Network responses write strictly to Room.</li></ul></li><li><strong>Offline Queueing:</strong><ul><li>App is offline. User types &quot;Hello&quot;.</li><li>ViewModel saves &quot;Hello&quot; to Room with <code>sync_status = PENDING</code>. The UI instantly shows it (optimistic update).</li><li>Enqueue a <code>WorkManager</code> task or start a job using <code>ConnectivityManager</code> callbacks.</li><li>When the internet restores, <code>WorkManager</code> intercepts the payload, posts to the WebSocket, updates the Room column to <code>SENT</code> upon success.</li></ul></li><li><strong>Pagination:</strong> Paging 3 loads older messages from Room natively as the user scrolls up.</li></ol><hr><h2 id="scenario-b-design-an-instagram-image-feed" tabindex="-1">Scenario B: Design an Instagram Image Feed <a class="header-anchor" href="#scenario-b-design-an-instagram-image-feed" aria-label="Permalink to &quot;Scenario B: Design an Instagram Image Feed&quot;">​</a></h2><p><strong>Requirements:</strong></p><ul><li>Extremely fast image loading.</li><li>Smooth scrolling without UI Jank.</li><li>Pagination.</li></ul><p><strong>Architecture Components:</strong></p><ol><li><strong>Data loading:</strong> REST API endpoint using offset/cursor pagination. Paging 3 <code>RemoteMediator</code> sits between the raw API DTO mapper and the Room Cache layout.</li><li><strong>Image Loading Engine (Glide/Coil):</strong><ul><li><strong>Memory Cache:</strong> L1 Cache. A HashMap maintaining decoded Bitmaps based on LRU (Least Recently Used) policies to render instantly on scroll.</li><li><strong>Disk Cache:</strong> L2 Cache. Encoded JPEGs/WebP saved to app scope cache directory so repeated app opens don&#39;t require network transfers.</li><li><strong>Downsampling:</strong> The raw backend image might be 4000x4000 pixels. The Image Pipeline must detect the ImageView boundaries (e.g., 500x500) and decode the Bitmap scaled to exactly that size to dodge <code>OutOfMemoryError</code> limits.</li></ul></li><li><strong>RecyclerView / LazyColumn:</strong><ul><li>Strict usage of <code>DiffUtil</code> so appending page 2 doesn&#39;t stutter the visible page 1 items.</li><li>Pre-fetching URLs using RecyclerView&#39;s <code>PreloadItem</code> mechanism so the next image downloads before the user scrolls to it.</li></ul></li></ol><hr><h2 id="scenario-c-massive-legacy-refactoring" tabindex="-1">Scenario C: Massive Legacy Refactoring <a class="header-anchor" href="#scenario-c-massive-legacy-refactoring" aria-label="Permalink to &quot;Scenario C: Massive Legacy Refactoring&quot;">​</a></h2><p><strong>Requirements:</strong></p><ul><li>Taking over a large Monolithic Java App (God Activities, MVC).</li><li>Transitioning it to Kotlin, Compose, MVVM, and Modularized architecture.</li></ul><p><strong>Strategy:</strong></p><ol><li><strong>Stop the Bleeding:</strong> Create a boundary. All <em>new</em> features are built strictly in Kotlin using MVVM/Compose in separate modules.</li><li><strong>Modularization first:</strong> Rip out generic utility functions (Date parsing, pure Network clients) into <code>core:utils</code> and <code>core:network</code> modules.</li><li><strong>Strangler Fig Pattern:</strong> Use Jetpack Navigation. Slowly extract single <code>Activity</code> screens into <code>Fragment/Compose</code> destinations hosted in a modern <code>MainActivity</code>.</li><li><strong>Unit Tests are mandatory:</strong> Before touching complex legacy God classes in Java, write heavy JUnit characterization tests tracking inputs and outputs perfectly to ensure refactoring logic into Kotlin UseCases doesn&#39;t cause hidden regressions.</li></ol>',23)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
